<script>
	const times = [
  {
    "start": 6,
    "end": 12,
		"perc_start": 0,
    "perc_end": 43.4
  },
  {
    "start": 12,
    "end": 16,
		"perc_start": 43.4,
    "perc_end": 62.5
  },
  {
    "start": 16,
    "end": 18,
		"perc_start": 62.5,
    "perc_end": 81.1
  },
  {
    "start": 18,
    "end": 21,
		"perc_start": 81.1,
    "perc_end": 100
  }
];
// should be 94.6 (fudged for prototype)

const voters = new Array(1000).fill(0).map((d, i) => {
	const timeBlock = times.filter(d => d.perc_end > (Math.random() * 100))[0];
	const time = timeBlock.start + (Math.random() * (timeBlock.end - timeBlock.start))
	return { id: i + 1,
	offset: time - 6}
});

let voterStack = voters.slice(0);
let voterQueue = [];
let test = "Test";
let ballot = new Array(6).fill(null);
let voted = [];

voters.map((d, i) => {
	setTimeout(() => {
		voterQueue = voterQueue.concat([d])
		voterStack[i] = null;
		test = "Test " + d.id;
	}, d.offset * 10000)
});

setInterval(() => {
	for(let i = 0; i < ballot.length; i++) {
		if(ballot[i] !== null) {
			if(ballot[i].hasVoted) {
				voted = voted.concat([ballot[i]]);
				ballot[i] = null;
			}
			else {
				ballot[i].hasVoted = true;
			}
		}
	}

	for(let i = 0; i < ballot.length; i++) {
		let emptySlot = ballot.indexOf(null);
		let nextVoter = voterQueue[voterQueue.length - 1 - i];
		if(emptySlot > -1 && nextVoter !== null && nextVoter !== undefined) {
			ballot = [...ballot.slice(0, emptySlot), nextVoter, ...ballot.slice(emptySlot + 1)];
			voterQueue[voterQueue.length - 1 - i] = null;
		}
	}


}, 250)
</script>

<style>
	.chart-container {
		width: 100%;
		height: 100%;
	}

	.v {
		border-radius: 20px;
		display: inline-block;
		width: 10px;
		height: 10px;
		margin: 5px;
	}

	.voter {
		border-radius: 20px;
		display: inline-block;
		width: 10px;
		height: 10px;
		margin: 5px;
	}

	.remaining .voter {
		border: 1px solid black;
	}
	.queue .voter {
		background: #222;
	}
	.ballot .voter {
		background: green;
	}
	.ballot .voter.empty {
		border: 1px solid green;
		background: #fff;
	}
	.voted .voter {
		background: #777;
	}
</style>

<div class="chart-container">
	<div class="remaining">
		<h5>Remaining voters:</h5>
		<span class="v"></span>
		{#each voterStack as voter}
			{#if voter !== null}<span class="voter"></span>{/if}
		{/each}
	</div>
	<div class="queue">
		<h5>Queue:</h5>
		<span class="v"></span>
		{#each voterQueue as voter}
			{#if voter !== null}<span class="voter"></span>{/if}
		{/each}
	</div>
	<div class="ballot">
		<h5>Polling station:</h5>
		<span class="v"></span>
		{#each ballot as voter}
			<span class="voter {voter === null ? "empty" : ""}"></span>
		{/each}
	</div>
	<div class="voted">
		<h5>Voted:</h5>
		<span class="v"></span>
		{#each voted as voter}
			<span class="voter"></span>
		{/each}
	</div>

</div>
